     1→"use client";
     2→
     3→import { useEffect, useState } from "react";
     4→import { useSearchParams } from "next/navigation";
     5→import { GuideGrid } from "@/components/gallery/guide-grid";
     6→import { SortTabs } from "@/components/gallery/sort-tabs";
     7→import { fetchGuides } from "@/lib/supabase/queries/guides";
     8→import { Loader2 } from "lucide-react";
     9→import type { Guide, SortOption } from "@/types";
    10→
    11→export default function Home() {
    12→  const searchParams = useSearchParams();
    13→  const query = searchParams.get("q") ?? "";
    14→  const [sort, setSort] = useState<SortOption>("trending");
    15→  const [guides, setGuides] = useState<Guide[]>([]);
    16→  const [loading, setLoading] = useState(true);
    17→
    18→  useEffect(() => {
    19→    setLoading(true);
    20→    fetchGuides(sort, query || undefined)
    21→      .then((data) => setGuides(data))
    22→      .catch(() => setGuides([]))
    23→      .finally(() => setLoading(false));
    24→  }, [sort, query]);
    25→
    26→  return (
    27→    <div>
    28→      {/* Header */}
    29→      <div className="mb-6 flex items-center justify-between">
    30→        <div>
    31→          <h1 className="text-2xl font-bold text-foreground">
    32→            {query ? `Results for "${query}"` : "Explore"}
    33→          </h1>
    34→          <p className="mt-1 text-sm text-muted-foreground">
    35→            {query ? `${guides.length} guide${guides.length !== 1 ? "s" : ""} found` : "Step-by-step guides for building with AI"}
    36→          </p>
    37→        </div>
    38→        <SortTabs active={sort} onChange={setSort} />
    39→      </div>
    40→
    41→      {/* Grid */}
    42→      {loading ? (
    43→        <div className="flex items-center justify-center py-20">
    44→          <Loader2 size={24} className="animate-spin text-muted-foreground" />
    45→        </div>
    46→      ) : (
    47→        <GuideGrid guides={guides} />
    48→      )}
    49→    </div>
    50→  );
    51→}
    52→

