    25→export default function GuideDetailPage() {
    26→  const { guideId } = useParams<{ guideId: string; slug: string }>();
    27→  const { user, profile, loading: authLoading } = useAuth();
    28→
    29→  const [guide, setGuide] = useState<GuideDetail | null>(null);
    30→  const [comments, setComments] = useState<Comment[]>([]);
    31→  const [liked, setLiked] = useState(false);
    32→  const [saved, setSaved] = useState(false);
    33→  const [following, setFollowing] = useState(false);
    34→  const [recommended, setRecommended] = useState<Guide[]>([]);
    35→  const [loading, setLoading] = useState(true);
    36→  const [notFound, setNotFound] = useState(false);
    37→
    38→  // Fetch guide data
    39→  useEffect(() => {
    40→    if (!guideId) return;
    41→
    42→    async function load() {
    43→      setLoading(true);
    44→      const guideData = await fetchGuideById(guideId);
    45→
    46→      if (!guideData) {
    47→        setNotFound(true);
    48→        setLoading(false);
    49→        return;
    50→      }
    51→
    52→      setGuide(guideData);
    53→      setNotFound(false);
    54→
    55→      // Parallel fetches
    56→      const [commentsData, recommendedData] = await Promise.all([
    57→        fetchGuideComments(guideId),
    58→        fetchRecommendedGuides(guideId, guideData.category_id),
    59→      ]);
    60→
    61→      setComments(commentsData);
    62→      setRecommended(recommendedData);
    63→      setLoading(false);
    64→    }
    65→
    66→    load();
    67→  }, [guideId]);
    68→
    69→  // Fetch user-specific status once auth is resolved
    70→  useEffect(() => {
    71→    if (!guide || !user) return;
    72→
    73→    async function loadStatus() {
    74→      const [likeStatus, saveStatus, followStatus] = await Promise.all([
    75→        checkLikeStatus(guide!.id, user!.id),
    76→        checkSaveStatus(guide!.id, user!.id),
    77→        guide!.profile && guide!.user_id !== user!.id
    78→          ? checkFollowStatus(user!.id, guide!.user_id)
    79→          : Promise.resolve(false),
    80→      ]);
    81→
    82→      setLiked(likeStatus);
    83→      setSaved(saveStatus);
    84→      setFollowing(followStatus);
    85→    }
    86→
    87→    loadStatus();
    88→  }, [guide?.id, user?.id]);
    89→
    90→  const isOwner = !!user && !!guide && user.id === guide.user_id;
    91→
    92→  const handleGuideUpdated = useCallback((updated: GuideDetail) => {
    93→    setGuide(updated);
    94→  }, []);
    95→
    96→  const handleGuideDeleted = useCallback(() => {
    97→    // Navigation handled by GuideActions
    98→  }, []);
    99→
   100→  if (loading || authLoading) {
   101→    return (
   102→      <div className="flex items-center justify-center py-20">
   103→        <Loader2 size={24} className="animate-spin text-muted-foreground" />
   104→      </div>
   105→    );
   106→  }
   107→
   108→  if (notFound || !guide) {
   109→    return (
   110→      <div className="flex flex-col items-center justify-center py-20 text-center">
   111→        <div className="mb-4 flex h-20 w-20 items-center justify-center rounded-2xl bg-muted">
   112→          <span className="text-3xl">🔍</span>
   113→        </div>
   114→        <h3 className="mb-2 text-lg font-semibold text-foreground">Guide not found</h3>
   115→        <p className="mb-4 max-w-sm text-sm text-muted-foreground">
   116→          This guide may have been deleted or doesn&apos;t exist.
   117→        </p>
   118→        <Link
   119→          href="/"
   120→          className="rounded-full bg-accent px-6 py-2.5 text-sm font-medium text-accent-foreground hover:opacity-90 transition-opacity"
   121→        >
   122→          Go home
   123→        </Link>
   124→      </div>
   125→    );
   126→  }
   127→
   128→  return (
   129→    <div>
   130→      {/* Back button */}
   131→      <div className="mb-6">
   132→        <Link
   133→          href="/"
   134→          className="inline-flex items-center gap-1.5 text-sm text-muted-foreground hover:text-foreground transition-colors"
   135→        >
   136→          <ArrowLeft size={16} />
   137→          Back
   138→        </Link>
   139→      </div>
   140→
   141→      {/* Two-column layout */}
   142→      <div className="flex flex-col gap-8 lg:flex-row">
   143→        {/* Left column */}
   144→        <div className="min-w-0 flex-1">
   145→          {/* Media */}
   146→          {guide.media && guide.media.length > 0 && (
   147→            <div className="mb-6">
   148→              <MediaGallery media={guide.media} />
   149→            </div>
   150→          )}
   151→
   152→          {/* Title + meta */}
   153→          <div className="mb-6">
   154→            <h1 className="mb-2 text-2xl font-bold text-foreground">{guide.title}</h1>
   155→            {guide.description && (
   156→              <p className="mb-3 text-sm text-muted-foreground">{guide.description}</p>
   157→            )}
   158→            <div className="flex flex-wrap items-center gap-2">
   159→              {guide.techs.length > 0 &&
   160→                guide.techs.map((tech) => (
   161→                  <span
   162→                    key={tech}
   163→                    className="rounded-full bg-muted px-2.5 py-0.5 text-xs font-medium text-muted-foreground"
   164→                  >
   165→                    {tech}
   166→                  </span>
   167→                ))}
   168→              {guide.category && (
   169→                <span className="rounded-full bg-accent/10 px-2.5 py-0.5 text-xs font-medium text-accent">
   170→                  {guide.category.name}
   171→                </span>
   172→              )}
   173→              <span className="text-xs text-muted-foreground">
   174→                {formatRelativeTime(guide.created_at)}
   175→              </span>
   176→            </div>
   177→          </div>
   178→
   179→          {/* Mobile: author card + actions */}
   180→          <div className="mb-6 flex flex-col gap-4 lg:hidden">
   181→            {guide.profile && (
   182→              <AuthorCard
   183→                author={guide.profile}
   184→                currentUserId={user?.id}
   185→                initialFollowing={following}
   186→              />
   187→            )}
   188→            <GuideActions
   189→              guideId={guide.id}
   190→              userId={user?.id}
   191→              initialLiked={liked}
   192→              initialSaved={saved}
   193→              likesCount={guide.likes_count}
   194→              savesCount={guide.saves_count}
   195→              isOwner={isOwner}
   196→              guide={guide}
   197→              onGuideUpdated={handleGuideUpdated}
   198→              onGuideDeleted={handleGuideDeleted}
   199→            />
   200→          </div>
   201→
   202→          {/* Chat timeline */}
   203→          {guide.chat_messages && guide.chat_messages.length > 0 && (
   204→            <div className="mb-8">
   205→              <ChatTimeline
   206→                messages={guide.chat_messages}
   207→                chapters={guide.timeline_chapters}
   208→                isOwner={isOwner}
