   222→        </div>
   223→
   224→        {/* Right column (desktop sidebar) */}
   225→        <div className="hidden w-80 flex-shrink-0 lg:block">
   226→          <div className="sticky top-20 flex flex-col gap-5">
   227→            {guide.profile && (
   228→              <AuthorCard
   229→                author={guide.profile}
   230→                currentUserId={user?.id}
   231→                initialFollowing={following}
   232→              />
   233→            )}
   234→            <GuideActions
   235→              guideId={guide.id}
   236→              userId={user?.id}
   237→              initialLiked={liked}
   238→              initialSaved={saved}
   239→              likesCount={guide.likes_count}
   240→              savesCount={guide.saves_count}
   241→              isOwner={isOwner}
   242→              guide={guide}
   243→              onGuideUpdated={handleGuideUpdated}
   244→              onGuideDeleted={handleGuideDeleted}
   245→            />
   246→            <Recommendations guides={recommended} />
   247→          </div>
   248→        </div>
   249→      </div>
   250→
   251→      {/* Mobile recommendations */}
   252→      {recommended.length > 0 && (
   253→        <div className="mt-8 lg:hidden">
   254→          <Recommendations guides={recommended} />
   255→        </div>
   256→      )}
   257→    </div>
   258→  );
   259→}
