     4→function isSupabaseConfigured() {
     5→  const url = process.env.NEXT_PUBLIC_SUPABASE_URL;
     6→  const key = process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY;
     7→  return url && key && url.startsWith("http") && key.length > 20;
     8→}
     9→
    10→export async function updateSession(request: NextRequest) {
    11→  if (!isSupabaseConfigured()) {
    12→    return NextResponse.next();
    13→  }
    14→
    15→  let supabaseResponse = NextResponse.next({ request });
    16→
    17→  const supabase = createServerClient(
    18→    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    19→    process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
    20→    {
    21→      cookies: {
    22→        getAll() {
    23→          return request.cookies.getAll();
    24→        },
    25→        setAll(cookiesToSet) {
    26→          cookiesToSet.forEach(({ name, value }) =>
    27→            request.cookies.set(name, value)
    28→          );
    29→          supabaseResponse = NextResponse.next({ request });
    30→          cookiesToSet.forEach(({ name, value, options }) =>
    31→            supabaseResponse.cookies.set(name, value, options)
    32→          );
    33→        },
    34→      },
    35→    }
    36→  );
    37→
    38→  await supabase.auth.getUser();
    39→
    40→  return supabaseResponse;
    41→}
